// Generated by Claude Sonnet 4.6

import {
  Button,
  Content,
  Modal,
  ModalBody,
  ModalFooter,
  ModalHeader,
  ModalVariant,
} from '@patternfly/react-core';
import { ExclamationTriangleIcon } from '@patternfly/react-icons';
import React, { useEffect } from 'react';

import styles from '@/components/SessionTimeoutModal/index.module.css';
import { useSessionTimeout } from '@/services/session/useSessionTimeout';

const URGENT_THRESHOLD_SECONDS = 20;

function WarningIcon(): React.ReactElement {
  return (
    <ExclamationTriangleIcon color="var(--pf-t--global--icon--color--status--warning--default)" />
  );
}

function SessionTimeoutModal(): React.ReactElement {
  const { isModalOpen, countdown, onExtend, onSignOut } = useSessionTimeout();

  useEffect(() => {
    if (!isModalOpen) {
      return;
    }
    function handleKey(e: KeyboardEvent): void {
      if (e.key === ' ' || e.key === 'Spacebar') {
        e.preventDefault();
        onExtend();
      }
    }
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [isModalOpen, onExtend]);

  const isUrgent = countdown <= URGENT_THRESHOLD_SECONDS;
  const ringClassName = isUrgent
    ? `${styles.countdownRing} ${styles.countdownRingUrgent}`
    : styles.countdownRing;

  return (
    <Modal
      variant={ModalVariant.small}
      isOpen={isModalOpen}
      onClose={() => {
        void onExtend();
      }}
      aria-labelledby="session-timeout-title"
      aria-describedby="session-timeout-body"
    >
      <ModalHeader
        title="Session about to expire"
        labelId="session-timeout-title"
        titleIconVariant={WarningIcon}
      />
      <ModalBody id="session-timeout-body">
        <div className={ringClassName} aria-hidden="true">
          {countdown}
        </div>
        <Content>
          <p>Your session will expire due to inactivity.</p>
          <p>
            Click <strong>Extend session</strong> within {countdown} seconds to stay signed in.
          </p>
          <p>If you take no action, you will be signed out and any unsaved changes may be lost.</p>
        </Content>
        <div className={styles.clearFloat} />
      </ModalBody>
      <ModalFooter>
        <Button variant="primary" onClick={onExtend}>
          Extend session
        </Button>
        <Button variant="link" onClick={onSignOut}>
          Sign out now
        </Button>
      </ModalFooter>
    </Modal>
  );
}

SessionTimeoutModal.displayName = 'SessionTimeoutModal';
export default SessionTimeoutModal;
